<?php
namespace App\Models;use Illuminate\Database\Eloquent\Concerns\HasUuids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class Workspace extends Model{use HasUuids,SoftDeletes;protected $fillable=['uuid','name','slug','status','owner_id','edition','timezone','currency','trial_ends_at','suspended_at','suspended_by','suspension_reason'];protected function casts():array{return ['trial_ends_at'=>'date','suspended_at'=>'datetime'];}public function uniqueIds():array{return ['uuid'];}public function owner(){return $this->belongsTo(User::class,'owner_id');}public function users(){return $this->belongsToMany(User::class)->withPivot(['role_key','status','invited_by','joined_at'])->withTimestamps();}public function domains(){return $this->hasMany(WorkspaceDomain::class);}public function settings(){return $this->hasOne(WorkspaceSetting::class);}public function subscription(){return $this->hasOne(Subscription::class);}public function onboardingSteps(){return $this->hasMany(WorkspaceOnboardingStep::class);}}
